mapper.insert:
INSERT INTO toss_market_price_snapshot (
    symbol, price_time, last_price, currency, raw_json
)
VALUES (
    #{symbol}, #{priceTime}, #{lastPrice}, #{currency}, #{rawJson}
)

INSERT INTO toss_orderbook_snapshot (
    symbol, orderbook_time, currency, best_ask_price, best_ask_volume,
    best_bid_price, best_bid_volume, spread, spread_bps, raw_json
)
VALUES (
    #{symbol}, #{orderbookTime}, #{currency}, #{bestAskPrice}, #{bestAskVolume},
    #{bestBidPrice}, #{bestBidVolume}, #{spread}, #{spreadBps}, #{rawJson}
)

INSERT INTO toss_trade_print (
    symbol, trade_time, price, volume, currency, raw_json
)
VALUES (
    #{symbol}, #{tradeTime}, #{price}, #{volume}, #{currency}, #{rawJson}
)
ON DUPLICATE KEY UPDATE
    currency = VALUES(currency),
    raw_json = VALUES(raw_json),
    fetched_at = CURRENT_TIMESTAMP

INSERT INTO toss_price_limit_snapshot (
    symbol, limit_time, upper_limit_price, lower_limit_price, currency, raw_json
)
VALUES (
    #{symbol}, #{limitTime}, #{upperLimitPrice}, #{lowerLimitPrice}, #{currency}, #{rawJson}
)

INSERT INTO toss_exchange_rate_snapshot (
    base_currency, quote_currency, rate, mid_rate, basis_point,
    rate_change_type, valid_from, valid_until, raw_json
)
VALUES (
    #{baseCurrency}, #{quoteCurrency}, #{rate}, #{midRate}, #{basisPoint},
    #{rateChangeType}, #{validFrom}, #{validUntil}, #{rawJson}
)

INSERT INTO toss_market_calendar_snapshot (
    market_country, query_date, today_date, today_open,
    previous_business_date, next_business_date, raw_json
)
VALUES (
    #{marketCountry}, #{queryDate}, #{todayDate}, #{todayOpen},
    #{previousBusinessDate}, #{nextBusinessDate}, #{rawJson}
)
